@page "/settings"
@using sv_18e3ad0dd9fa479cae98c3be4f1b52dd.Models
@using sv_18e3ad0dd9fa479cae98c3be4f1b52dd.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <aside class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <nav class="settings-nav">
            @foreach (var section in _sections)
            {
                <button class="nav-tab @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Icon</span>
                    @section.Label
                </button>
            }
        </nav>
    </aside>

    <section class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastMessage is not null)
        {
            <div class="toast-notification @(_toastFading ? "fade-out" : "")">
                <span>✓</span> @_toastMessage
            </div>
        }
    </section>
</div>

@* ──── Revoke Session Confirmation Modal ──── *@
@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop show" @onclick="() => _sessionToRevoke = null"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="() => _sessionToRevoke = null"></button>
                </div>
