@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    // ── Loading ──
    private bool _loading = true;

    // ── Toast ──
    private string? _toastMessage;
    private bool _toastFading;
    private CancellationTokenSource? _toastCts;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // ── Notifications state ──
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private Dictionary<string, bool> _channelMuteStates = new();

    // ── Security state ──
    private SecuritySettings? _security;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _twoFactorEnabled;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance state ──
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] AvailableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        ApplyProfile(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _emailNotifications = notif.EmailNotifications;
        _pushNotifications = notif.PushNotifications;
        _weeklyDigest = notif.WeeklyDigest;
        foreach (var ch in MockSettingsService.AllChannels)
        {
            _channelMuteStates[ch] = notif.MutedChannels.Contains(ch);
        }

        // Security
        _security = securityTask.Result;
        _twoFactorEnabled = _security.TwoFactorEnabled;

        // Appearance
        var appearance = appearanceTask.Result;
        _theme = appearance.Theme;
        _fontSize = appearance.FontSize;
        _language = appearance.Language;
        _compactMode = appearance.CompactMode;

        _loading = false;
    }

    // ── Helpers ──

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task ShowToast(string message)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastFading = false;
        StateHasChanged();

        try
        {
            await Task.Delay(2500, token);
            _toastFading = true;
            StateHasChanged();
            await Task.Delay(500, token);
            _toastMessage = null;
            _toastFading = false;
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile actions ──

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }

    // ── Notification actions ──

    private async Task SaveNotifications()
    {
        var mutedChannels = _channelMuteStates
            .Where(kv => kv.Value)
            .Select(kv => kv.Key)
            .ToList();

        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            mutedChannels);

        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    // ── Security actions ──

    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _security = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevokeSession(ActiveSession session) => _sessionToRevoke = session;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessionToRevoke = null;
        _security = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Session revoked.");
    }

    // ── Appearance actions ──

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSizeCss => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem",
    };

    private string PreviewBgColor => _theme switch
    {
        "Dark" => "#1e1e1e",
        _ => "#ffffff",
    };

    private string PreviewTextColor => _theme switch
    {
        "Dark" => "#d4d4d4",
        _ => "#212529",
    };

    // ── Render fragments ──

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <h3 class="section-title">Profile</h3>

        <div class="card settings-card">
            <div class="card-body">
                <div class="avatar-area mb-4">
                    <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
                    <div class="avatar-url-display">
                        <label class="form-label text-muted small">Avatar URL</label>
                        <div class="text-muted small text-break">@_avatarUrl</div>
                    </div>
                </div>

                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="3" @bind="_bio"></textarea>
                </div>

                <div class="d-flex gap-2">
                    <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                    <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
                </div>
            </div>
        </div>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <h3 class="section-title">Notifications</h3>

        <div class="card settings-card">
            <div class="card-body">
                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Email Notifications</div>
                        <div class="text-muted small">Receive updates via email</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_emailNotifications" />
                    </div>
                </div>

                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Push Notifications</div>
                        <div class="text-muted small">Receive browser push notifications</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_pushNotifications" />
                    </div>
                </div>

                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Weekly Digest</div>
                        <div class="text-muted small">Get a weekly summary email</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_weeklyDigest" />
                    </div>
                </div>

                <hr />
                <h6>Channel Muting</h6>
                <div class="channel-list">
                    @foreach (var channel in _channelMuteStates.Keys.ToList())
                    {
                        var ch = channel;
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                                   checked="@_channelMuteStates[ch]"
                                   @onchange="e => _channelMuteStates[ch] = (bool)(e.Value ?? false)" />
                            <label class="form-check-label" for="@($"ch-{ch}")">@ch <span class="text-muted small">(muted)</span></label>
                        </div>
                    }
                </div>

                <div class="mt-3">
                    <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
                </div>
            </div>
        </div>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <h3 class="section-title">Security</h3>

        @* ── Change Password Panel ── *@
        <div class="card settings-card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center expandable-header"
                 @onclick="() => _changePasswordExpanded = !_changePasswordExpanded"
                 style="cursor: pointer;">
                <span class="fw-semibold">Change Password</span>
                <span>@(_changePasswordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_changePasswordExpanded)
            {
                <div class="card-body">
                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                </div>
            }
        </div>

        @* ── Two-Factor Authentication ── *@
        <div class="card settings-card mb-3">
            <div class="card-body">
                <div class="toggle-row">
                    <div>
                        <div class="fw-semibold">Two-Factor Authentication</div>
                        <div class="text-muted small">
                            Status:
                            <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                                @(_twoFactorEnabled ? "Enabled" : "Disabled")
                            </span>
                        </div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_twoFactorEnabled" />
                    </div>
                </div>

                @if (_security?.LastPasswordChange is not null)
                {
                    <div class="text-muted small mt-2">
                        Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </div>
                }
            </div>
        </div>

        @* ── Active Sessions ── *@
        <div class="card settings-card">
            <div class="card-body">
                <h6 class="mb-3">Active Sessions</h6>
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @if (_security is not null)
                            {
                                @foreach (var session in _security.Sessions)
                                {
                                    var isCurrentSession = session == _security.Sessions[0];
                                    <tr>
                                        <td>
                                            @session.Device
                                            @if (isCurrentSession)
                                            {
                                                <span class="badge bg-info ms-1">Current</span>
                                            }
                                        </td>
                                        <td>@session.Location</td>
                                        <td>@FormatLastActive(session.LastActive)</td>
                                        <td>
                                            @if (!isCurrentSession)
                                            {
                                                <button class="btn btn-outline-danger btn-sm"
                                                        @onclick="() => RequestRevokeSession(session)">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <h3 class="section-title">Appearance</h3>

        <div class="card settings-card mb-3">
            <div class="card-body">
                <div class="mb-4">
                    <h6>Theme</h6>
                    <div class="d-flex gap-3">
                        @foreach (var t in new[] { "Light", "Dark", "System" })
                        {
                            var theme = t;
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Font Size</h6>
                    <div class="d-flex gap-3">
                        @foreach (var fs in new[] { "Small", "Medium", "Large" })
                        {
                            var size = fs;
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" style="max-width: 250px;"
                            @bind="_language">
                        @foreach (var lang in AvailableLanguages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="toggle-row mb-0">
                    <div>
                        <div class="fw-semibold">Compact Mode</div>
                        <div class="text-muted small">Reduce padding and spacing</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_compactMode" />
                    </div>
                </div>
            </div>
        </div>

        @* ── Live Preview ── *@
        <div class="card settings-card mb-3">
            <div class="card-header fw-semibold">Live Preview</div>
            <div class="card-body p-0">
                <div class="live-preview"
                     style="background-color: @PreviewBgColor; color: @PreviewTextColor; font-size: @PreviewFontSizeCss; padding: @(_compactMode ? "0.5rem" : "1.25rem");">
                    <h6 style="color: @PreviewTextColor;">Dashboard Overview</h6>
                    <p class="mb-2">This is a preview of how your content will appear with the selected settings.</p>
                    <div class="d-flex gap-2 flex-wrap">
                        <span class="badge bg-primary">Badge</span>
                        <span class="badge bg-success">Active</span>
                        <span class="badge bg-warning text-dark">Pending</span>
                    </div>
                    <hr style="border-color: @(_theme == "Dark" ? "#444" : "#dee2e6");" />
                    <p class="mb-0 small" style="color: @PreviewTextColor;">
                        Theme: @_theme · Size: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                    </p>
                </div>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
    };
}

