+                        <input class="form-check-input" type="checkbox" role="switch" @bind="_compactMode" />
+                    </div>
+                </div>
+            </div>
+        </div>
+
+        @* ── Live Preview ── *@
+        <div class="card settings-card mb-3">
+            <div class="card-header fw-semibold">Live Preview</div>
+            <div class="card-body p-0">
+                <div class="live-preview"
+                     style="background-color: @PreviewBgColor; color: @PreviewTextColor; font-size: @PreviewFontSizeCss; padding: @(_compactMode ? "0.5rem" : "1.25rem");">
+                    <h6 style="color: @PreviewTextColor;">Dashboard Overview</h6>
+                    <p class="mb-2">This is a preview of how your content will appear with the selected settings.</p>
+                    <div class="d-flex gap-2 flex-wrap">
